import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import Layout from './components/Layout';
import HomePage from './components/HomePage';
import PleadingsPage from './components/PleadingsPage';
import MotionsPage from './components/MotionsPage';
import FormsPage from './components/FormsPage';
import ResourcesPage from './components/ResourcesPage';
import MultiSectionForm from './components/MultiSectionForm';

const DeclarationPage = () => {
  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Routes>
        <Route 
          path="/new" 
          element={
            <div className="space-y-6">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">New Declaration</h2>
              <MultiSectionForm />
            </div>
          } 
        />
        <Route 
          path="/search" 
          element={
            <div className="space-y-6">
              <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow">
                <input
                  type="search"
                  placeholder="Search declarations..."
                  className="w-full px-4 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>
          } 
        />
        <Route 
          path="/edit" 
          element={
            <div className="space-y-6">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Edit Declaration</h2>
              <MultiSectionForm />
            </div>
          } 
        />
        <Route 
          index 
          element={
            <div className="text-center space-y-4">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Declaration Management</h2>
              <p className="text-gray-600 dark:text-gray-400">Please select an option from the menu to continue</p>
            </div>
          } 
        />
      </Routes>
    </div>
  );
};

function App() {
  const [isDarkMode, setIsDarkMode] = useState(false);

  useEffect(() => {
    const darkModePref = localStorage.getItem('darkMode') === 'true';
    setIsDarkMode(darkModePref);
    if (darkModePref) {
      document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.documentElement.classList.toggle('dark');
    localStorage.setItem('darkMode', !isDarkMode);
  };

  return (
    <Router>
      <Layout darkMode={isDarkMode} toggleDarkMode={toggleDarkMode}>
        <AppRoutes />
      </Layout>
    </Router>
  );
}

function AppRoutes() {
  const navigate = useNavigate();

  return (
    <Routes>
      <Route path="/" element={<HomePage onNavigate={navigate} />} />
      <Route path="/pleadings" element={<PleadingsPage />} />
      <Route path="/motions" element={<MotionsPage />} />
      <Route path="/forms" element={<FormsPage />} />
      <Route path="/resources/*" element={<ResourcesPage />} />
      <Route path="/declaration/*" element={<DeclarationPage />} />
    </Routes>
  );
}

export default App;
